SELECT count(*) FROM keyword, movie_keyword, title, kind_type, cast_info, role_type, name WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND title.kind_id = kind_type.id AND cast_info.movie_id = title.id AND cast_info.role_id = role_type.id AND cast_info.person_id = name.id;